import sqlite3, datetime
DB = 'coach_tahseeli/tahseeli.db'
NOW = datetime.datetime.now(datetime.timezone.utc).isoformat()

NAMES = {
    8:  'الكهرباء الساكنة',
    9:  'التيار الكهربائي والدوائر الكهربائية',
    10: 'المغناطيسية والكهرومغناطيسية',
    16: 'علاقة الفيزياء بالعلوم الأخرى وتطبيقاتها',
}

conn = sqlite3.connect(DB)
cur = conn.cursor()

def ins(txt,a,b,c,d,ans,exp,snum,diff='متوسط'):
    cur.execute("""INSERT INTO pro_license_questions
        (text,option_a,option_b,option_c,option_d,answer,explanation,
         standard_num,standard_name,q_type,difficulty,is_active,created_at)
        VALUES(?,?,?,?,?,?,?,?,?,'mcq',?,1,?)""",
        (txt,a,b,c,d,ans,exp,str(snum),NAMES[snum],diff,NOW))

